+"use client";
+
+import { useEffect, useState, useCallback } from "react";
+
+interface BeforeInstallPromptEvent extends Event {
+  readonly platforms: string[];
+  readonly userChoice: Promise<{
+    outcome: "accepted" | "dismissed";
+    platform: string;
+  }>;
+  prompt(): Promise<void>;
+}
+
+interface PWAInstallState {
+  isInstallable: boolean;
+  isInstalled: boolean;
+  isIOS: boolean;
+  canPrompt: boolean;
+}
+
+/**
+ * Hook to handle PWA installation prompts.
+ * Captures the beforeinstallprompt event and provides methods to trigger installation.
+ */
+export function usePWAInstall() {
+  const [deferredPrompt, setDeferredPrompt] = useState<BeforeInstallPromptEvent | null>(null);
+  const [state, setState] = useState<PWAInstallState>({
+    isInstallable: false,
+    isInstalled: false,
+    isIOS: false,
+    canPrompt: false,
+  });
+
+  useEffect(() => {
+    // Detect iOS
+    const isIOS =
+      /iPad|iPhone|iPod/.test(navigator.userAgent) ||
+      (navigator.platform === "MacIntel" && navigator.maxTouchPoints > 1);
+
+    // Check if already installed
+    const isInstalled =
+      window.matchMedia("(display-mode: standalone)").matches ||
+      (window.navigator as Navigator & { standalone?: boolean }).standalone === true;
+
+    setState((prev) => ({
+      ...prev,
+      isIOS,
+      isInstalled,
+    }));
+
+    // Listen for beforeinstallprompt event
+    const handleBeforeInstallPrompt = (e: Event) => {
+      e.preventDefault();
+      const promptEvent = e as BeforeInstallPromptEvent;
+      setDeferredPrompt(promptEvent);
+      setState((prev) => ({
+        ...prev,
+        isInstallable: true,
+        canPrompt: true,
+      }));
+    };
+
+    // Listen for app installed event
+    const handleAppInstalled = () => {
+      setDeferredPrompt(null);
+      setState((prev) => ({
+        ...prev,
+        isInstalled: true,
+        isInstallable: false,
+        canPrompt: false,
+      }));
+    };
+
+    window.addEventListener("beforeinstallprompt", handleBeforeInstallPrompt);
+    window.addEventListener("appinstalled", handleAppInstalled);
+
+    return () => {
+      window.removeEventListener("beforeinstallprompt", handleBeforeInstallPrompt);
+      window.removeEventListener("appinstalled", handleAppInstalled);
+    };
+  }, []);
+
+  const promptInstall = useCallback(async () => {
+    if (!deferredPrompt) {
+      return { outcome: "dismissed" as const, reason: "no-prompt" };
+    }
+
+    try {
+      await deferredPrompt.prompt();
+      const { outcome } = await deferredPrompt.userChoice;
+
+      if (outcome === "accepted") {
+        setDeferredPrompt(null);
+        setState((prev) => ({
+          ...prev,
+          canPrompt: false,
+        }));
+      }
+
+      return { outcome, reason: null };
+    } catch (error) {
+      console.error("[PWA] Install prompt error:", error);
+      return { outcome: "dismissed" as const, reason: "error" };
+    }
+  }, [deferredPrompt]);
+
+  return {
+    ...state,
+    promptInstall,
+  };
+}
